#include <iostream>
using namespace std;

int main() {
    // Simple statements
    int x = 5;
    x = x + 2;
    cout << x << endl;

    // Block - can be used anywhere a single statement is expected
    if (true) {
        cout << "Inside block" << endl;
        int y = 10;
        cout << y << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Traditional initialization
    int age = 25;
    double price = 9.99;

    // Uniform initialization (C++11)
    int score{100};
    char grade{'A'};

    cout << "Age: " << age << endl;
    cout << "Price: " << price << endl;
    cout << "Score: " << score << endl;
    cout << "Grade: " << grade << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 10, b = 3;
    cout << "a + b = " << a + b << endl;
    cout << "a - b = " << a - b << endl;
    cout << "a * b = " << a * b << endl;
    cout << "a / b = " << a / b << " (integer division)" << endl;
    cout << "a % b = " << a % b << " (remainder)" << endl;

    double x = 10.0, y = 3.0;
    cout << "x / y = " << x / y << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int x = 5;
    cout << "x = " << x << endl;
    cout << "++x = " << ++x << endl;  // x becomes 6, then prints 6
    cout << "x++ = " << x++ << endl;  // prints 6, then x becomes 7
    cout << "Now x = " << x << endl;

    int y = 5;
    cout << "y-- = " << y-- << endl;  // prints 5, then y becomes 4
    cout << "--y = " << --y << endl;  // y becomes 3, then prints 3

    return 0;
}
